my $url = $args->{url};
$url =~ s|/+$||;
$url = 'https://' . $url unless $url =~ m{^https?://}i;

# ---- HTTP Status & Response Time ----
my $http_info = _safe_curl_get_code_and_time($url, 15);
my ($http_code, $resp_time) = split(':', $http_info);
$http_code //= 'ERR';
my $rt = defined $resp_time && $resp_time ne '' ? sprintf('%.0f', $resp_time * 1000) : '-';

# ---- SSL Expiry ----
my $ssl_expiry = '-';
my $verbose = _safe_curl_verbose($url, 12);
if ($verbose =~ /expire date:\s*(.+)/i) { $ssl_expiry = $1; }

# ---- robots.txt ----
my $robots_code = _safe_curl_get_http_code($url . '/robots.txt', 8);
my $robots_status = ($robots_code eq '200') ? 'YES' : ($robots_code eq '404') ? 'no' : ($robots_code || 'ERR');

# ---- sitemap.xml ----
my $sitemap_code = _safe_curl_get_http_code($url . '/sitemap.xml', 8);
my $sitemap_status = ($sitemap_code eq '200') ? 'YES' : ($sitemap_code eq '404') ? 'no' : ($sitemap_code || 'ERR');

# ---- Format Table ----
my $title = 'Deploy Check: ' . $url;
my $sep = '-' x (length($title) + 4);
my $table = $sep . "\n| " . $title . " |\n" . $sep . "\n" .
    "| Check           | Result" . "\n" .
    "|-----------------|----------------------------------------------" . "\n" .
    "| HTTP Status     | $http_code" . "\n" .
    "| Response Time   | $rt ms" . "\n" .
    "| SSL Expiry      | $ssl_expiry" . "\n" .
    "| robots.txt      | $robots_status" . "\n" .
    "| sitemap.xml     | $sitemap_status" . "\n" .
    $sep;

return {
    url              => $url,
    http_status      => $http_code + 0,
    response_time_ms => $rt,
    ssl_expiry       => $ssl_expiry,
    robots_txt       => $robots_status,
    sitemap_xml      => $sitemap_status,
    table            => $table,
};

my $base   = $args->{base}   // 'USD';
my $target = $args->{target} // 'RUB';
my $r = _safe_http_get_json("https://api.exchangerate-api.com/v4/latest/$base");
die "HTTP error: $r->{status} - $r->{reason}" unless $r->{success};
my $d = $r->{data};
my $rate = $d->{rates}{$target};
die "Target currency '$target' not found." unless defined $rate;
return {
    base       => $base,
    target     => $target,
    rate       => $rate + 0.0,
    date       => $d->{date},
    source     => "exchangerate-api.com",
};

my $text = $args->{text} or die "Missing required parameter: text";
my $src = $args->{source} // 'auto';
my $tgt = $args->{target} // 'ru';
my $pair = $src eq 'auto' ? $tgt : "$src|$tgt";
my $e = _uri_escape_utf8($text);
my $url = "https://api.mymemory.translated.net/get?q=$e&langpair=$pair";
my $r = _safe_http_get_json($url);
die "HTTP error: $r->{status} - $r->{reason}" unless $r->{success};
my $d = $r->{data};
my $translated = $d->{responseData}{translatedText} // '';
my $detected   = $d->{responseData}{detectedLanguage} // $src;
my $match      = ($d->{responseData}{match} // 0) + 0;
return {
    original_text   => $text,
    translated_text => $translated,
    source_lang     => $detected,
    target_lang     => $tgt,
    match_quality   => $match,
};

my $city = $args->{city} or die "Missing required parameter: 'city'";
my $r = _safe_http_get_json("https://wttr.in/$city?format=j1");
die "HTTP error: $r->{status} - $r->{reason}" unless $r->{success};
my $d = $r->{data};
return {
    requested_city => $city,
    city           => ($d->{nearest_area}[0]{areaName}[0]{value} // $city),
    country        => ($d->{nearest_area}[0]{country}[0]{value} // "?"),
    temp_C         => ($d->{current_condition}[0]{temp_C} // "?") + 0,
    feels_like_C   => ($d->{current_condition}[0]{FeelsLikeC} // "?") + 0,
    humidity       => ($d->{current_condition}[0]{humidity} // "?") + 0,
    wind_speed_kmh => ($d->{current_condition}[0]{windspeedKmph} // "?") + 0,
    wind_dir       => ($d->{current_condition}[0]{winddir16Point} // "?"),
    desc           => ($d->{current_condition}[0]{weatherDesc}[0]{value} // "?"),
    obs_time       => ($d->{current_condition}[0]{observation_time} // "?"),
};
